+
+type AspectRecord<T extends readonly Trait[]> = UnionToIntersection<T[number] extends Trait<infer S> ? TraitRecord<S> : never>;
+type UnionToIntersection<T> = (T extends any ? (value: T) => void : never) extends (value: infer R) => void ? R : never;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends readonly [Trait, Trait, ...Trait[]]>(...inputs: T): Aspect<T> {
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+
+    for (const input of inputs) {
+        const flattened = isAspect(input) ? input.traits : [input];
+        for (const trait of flattened) {
+            if (isRelation(trait)) throw new Error('Koota: Relations cannot be constituents of an aspect.');
+            for (const field of Object.keys(trait.schema)) {
+                if (fields.has(field)) throw new Error(`Koota: Aspect field "${field}" is defined by multiple traits.`);
+                fields.add(field);
+            }
+            traits.push(trait);
+        }
+    }
+
+    return Object.freeze({
+        [$aspect]: true as const,
+        id: aspectId++,
+        traits: Object.freeze(traits) as unknown as T,
+        schema: Object.freeze(Object.assign({}, ...traits.map((trait) => trait.schema))),
+    });
+}
+
+export function hasAspect(entity: Entity, aspect: Aspect): boolean {
+    const world = getEntityWorld(entity);
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect<T extends readonly Trait[]>(entity: Entity, aspect: Aspect<T>): AspectRecord<T> | undefined {
+    if (!hasAspect(entity, aspect)) return undefined;
+    const world = getEntityWorld(entity);
+    return Object.assign({}, ...aspect.traits.map((trait) => getTrait(world, entity, trait))) as AspectRecord<T>;
+}
+
+export function setAspect(entity: Entity, aspect: Aspect, value: Record<string, unknown>): void {
+    const world = getEntityWorld(entity);
+    for (const trait of aspect.traits) {
+        const partial = pickTraitValues(trait, value);
+        if (Object.keys(partial).length) setTrait(world, entity, trait, partial);
+    }
+}
+
+export function addAspect(entity: Entity, aspect: Aspect, value: Record<string, unknown> = {}): void {
+    const world = getEntityWorld(entity);
+    for (const trait of aspect.traits) {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, pickTraitValues(trait, value)] as ConfigurableTrait);
+    }
+}
+
+export function removeAspect(entity: Entity, aspect: Aspect): void {
+    removeTrait(getEntityWorld(entity), entity, ...aspect.traits);
+}
+
+export function pickTraitValues(trait: Trait, value: Record<string, unknown>): TraitValue<any> {
+    const partial: Record<string, unknown> = {};
+    for (const field of Object.keys(trait.schema)) if (field in value) partial[field] = value[field];
+    return partial;
